module RefModule(
    input clk, reset, load,
    input [4:0] data_in,
    output reg [4:0] count);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            count <= 5'b0;
        else if (load)
            count <= data_in;
        else
            count <= count + 1;
    end
endmodule
